var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뻔하군요. 녀석들은 그게 뭔지도 모르면서 관리국이 노리는 물건이니 눈독을 들인 겁니다.","JPN":"見え見えですね。やつらはそれが何かもわからないのに管理局が狙っているから目を付けたんです。","ENG":"It's obvious. They don't even know what it is, but since the Administration is after it, they targeted it.","TWN":"很明顯他們根本不知道那是什麼東西，只是因為管理局盯上了，所以才會感興趣。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조만간 관리국이 그 목에 현상금을 걸 가능성이 높겠죠.","JPN":"近いうちに管理局がやつらに懸賞金を懸ける可能性が高いですね。","ENG":"Soon, the Administration will likely put a bounty on their heads.","TWN":"管理局很快就會發出懸賞吧。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"얼마짜리 의뢰인지 알 수 없으니, 관리국 공지를 기다릴까요?","JPN":"いくらになるかは不明なので、管理局の告知があるまで待ちますか？","ENG":"Since we don't know the amount of the reward for the request, should we wait for the Administration's notice?","TWN":"還不知道委託的金額，要不要等管理局的通知？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 우리가 먼저 움직입니다.","JPN":"いいえ。先に動きましょう。","ENG":"No. We need to act first.","TWN":"不，我們要先行動。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정보 경쟁에서 우위에 선 지금이 다른 태스크포스를 앞지를 타이밍이니까요.","JPN":"情報競争で優位に立っている今こそが他のタスクフォースに勝つタイミングですから。","ENG":"We have the information advantage right now, so now's the time to get ahead of the other TASKFORCEs.","TWN":"現在我們在資訊競爭中佔優勢，是超越其他特遣勢力的好時機。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"후후, 역시 부사장님이라면 그렇게 말씀하실 줄 알았어요.","JPN":"ふふ、副社長ならそう言うと思いました。","ENG":"Haha, I knew you would say something like that, Vice President.","TWN":"嘿，我就知道，如果是副總的話，肯定會這麼說的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양은 그 강도들의 행방을 찾으세요.","JPN":"シズカさんはその強盗の行方を追ってください。","ENG":"Seo Yoon, find out where the thieves went.","TWN":"徐芸，請你找到那些強盜的下落。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금쯤 이면세계에서 온 물질을 장물 취급하며 암시장에 내다 팔 궁리나 하는 놈들이 있을 지도 모릅니다.","JPN":"今頃、裏世界の物質を盗品として闇市場に売払おうと考えている輩がいるかもしれません。","ENG":"By now, there might be people planning to sell materials from the Counterside as contraband in the black market.","TWN":"現在可能會有一些傢伙把異界來的東西放到黑市上出售。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"맡겨주세요. 블랙네트워크 쪽 소식통은 제가 또 전문이니까요.","JPN":"お任せください。ブラックネットワークの動きは私の専門ですから。","ENG":"Leave it to me. I'm quite good with informants in the Dark Network.","TWN":"交給我吧。搜索黑色網路那邊的消息，我可是專家。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"추락체가 있던 현장은 새로 온 직원에게 분석을 맡기겠습니다.","JPN":"落下体があった現場の分析は新しい社員に任せます。","ENG":"I'll assign the analysis of the site where the fallen object was to a new employee.","TWN":"墜落物所在的現場將交給新來的進行分析。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양도 알다시피 지금 회사엔 움직일 인력이 많지 않으니, 현장지원은 기대마시길.","JPN":"シズカさんも知ってのとおり現在会社には動かせる人手が少ないので、サポートはないと思ってください。","ENG":"As you know, Seo Yoon, there aren't many people available in the company right now, so don't expect any support.","TWN":"你也知道，現在公司沒有太多可以動員的人手，所以不要指望有支援。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"곰돌씨, 꽃차 한 잔 더 마실래요?","JPN":"クマさん、花茶もう1杯いかがですか？","ENG":"Mr. Bear, would you like another cup of flower tea?","TWN":"熊熊先生，要再喝一杯花茶嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MRBEAR_NPC_NULL_NULL","text":{"KOREA":"음- 음- 솔로베가 만든 차는 얼마든지 마셔도 좋아.","JPN":"う～んう～ん、ソロベーが淹れるお茶はいつ飲んでもいい。","ENG":"Mmm, mm... I'm happy to drink as much tea as Solovey makes.","TWN":"嗯嗯，蘇羅薇泡的茶多少我都喝得下。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MRBEAR_NPC_NULL_NULL","text":{"KOREA":"솔로베의 꽃차는 정말 향긋하구나. 백화점에서 늘 맡던 화장품 냄새만큼은 아니지만 말이야.","JPN":"ソロベーの花茶は本当にいい香りがする。いつもデパートで嗅いでいた化粧品の匂いほどではないけど。","ENG":"Solovey's flower tea is really fragrant. It's not quite as strong as the perfume smell I used to smell at the department store, though.","TWN":"蘇羅薇的花茶真的很香，雖然沒有百貨公司裡常聞到的化妝品味道那麼濃郁。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 그 냄새 별로에요. 정원에선 그보다 향긋한 꽃이 훨씬 많은 걸요.","JPN":"私はその匂い苦手です。庭園にはそれよりいい香りのお花がもっとたくさんあります。","ENG":"I don't like that smell much. There are far more fragrant flowers in the garden.","TWN":"我不太喜歡那個味道，我覺得花園裡的花比較香。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MRBEAR_NPC_NULL_NULL","text":{"KOREA":"그래? 나도 한 번 가봤으면 좋겠다.","JPN":"そうか、私も一度行ってみたいな。","ENG":"I see. I'd like to visit there sometime.","TWN":"原來如此。我也想去看看啊。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 다신 못 돌아갈 거예요. 패리가 돌아가는 문이 닫혔다고 그랬거든요.","JPN":"それが、もう二度と戻れないんです。扉が閉ざされたって、パリーが言ってましたから。","ENG":"But I'll never be able to go back. Parry said the door to return is closed.","TWN":"但是再也回不去了，佩瑞是這麼說的。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MRBEAR_NPC_NULL_NULL","text":{"KOREA":"저런. 돌아갈 수 없게 됐구나.","JPN":"そうか。戻れなくなったのか。","ENG":"Oh, so you can't go back anymore.","TWN":"哎呀，看來是回不去了。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MRBEAR_NPC_NULL_NULL","text":{"KOREA":"그럼 이제부턴 여기가 솔로베의 집이 되는 건가?","JPN":"ではこれからはここがソロベーの家なのか？","ENG":"Does that mean this is Solovey's home from now on?","TWN":"那麼以後這裡就是蘇羅薇的家了嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"내 집…?","JPN":"私の家……？","ENG":"My home…?","TWN":"呃……"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래도 될까요? 함부로 그런 말 했다가 언니가 싫어하면…","JPN":"それでもいいんですか？　むやみにそんなこと言って、姉さんに嫌われたら……","ENG":"Is it okay? But what if Sis doesn't like it...","TWN":"這我也不太……"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"누구랑 얘기하는 거야?","JPN":"誰と話しているの？","ENG":"Who are you talking to?","TWN":"你在和誰說話？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"힉끅-","JPN":"ひっくー","ENG":"*Hiccup*","TWN":"唔……"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"SURPRISE2"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"딸꾹질?","JPN":"しゃっくり？","ENG":"Hiccups?","TWN":"打嗝？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"언니…?","JPN":"姉さん……？","ENG":"Sis...?","TWN":"姊姊……？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"SURPRISE2"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"}}}}]`);export{e as default};